function SetupInput({
  label,
  value,
  onChange,
  type = 'text',
}: {
  label: string;
  value: string;
  onChange: (value: string) => void;
  type?: 'text' | 'number';
}): JSX.Element {
  return (
    <label className="flex flex-col gap-1 text-[11px] text-muted">
      {label}
      <input
        type={type}
        value={value}
        onChange={(e) => onChange(e.currentTarget.value)}
        className="h-8 rounded border border-border bg-surface px-2 text-xs text-foreground"
      />
    </label>
  );
}

function SetupSelect({
  label,
  value,
  options,
  onChange,
}: {
  label: string;
  value: string;
  options: readonly (readonly [string, string])[];
  onChange: (value: string) => void;
}): JSX.Element {
  return (
    <label className="flex flex-col gap-1 text-[11px] text-muted">
      {label}
      <select
        value={value}
        onChange={(e) => onChange(e.currentTarget.value)}
        className="h-8 rounded border border-border bg-surface px-2 text-xs text-foreground"
      >
        {options.map(([optionValue, labelText]) => (
          <option key={optionValue} value={optionValue}>
            {labelText}
          </option>
        ))}
      </select>
    </label>
  );
}

function SetupButton({
  busy,
  onClick,
  children,
}: {
  busy: boolean;
  onClick: () => void;
  children: string;
}): JSX.Element {
  return (
    <button
      type="button"
      disabled={busy}
      onClick={onClick}
      className="mt-3 rounded border border-border bg-surface px-3 py-1.5 text-xs font-medium text-foreground hover:bg-surface-strong disabled:cursor-wait disabled:opacity-60"
    >
      {busy ? 'Applying...' : children}
    </button>
  );
}

function Metric({ label, value }: { label: string; value: string }): JSX.Element {
  return (
    <div className="rounded border border-border bg-surface p-2">
      <div className="text-[10px] uppercase text-muted">{label}</div>
      <div className="mt-1 font-mono text-sm text-foreground">{value}</div>
    </div>
  );
}

